import{_ as o,o as t,c as n,ag as a}from"./chunks/framework.D4O_uTxf.js";const p=JSON.parse('{"title":"Documentation Organization Governance","description":"","frontmatter":{},"headers":[],"relativePath":"upstream-governance/trace/fragemented/AGENTS.md","filePath":"upstream-governance/trace/fragemented/AGENTS.md","lastUpdated":1771844172000}'),s={name:"upstream-governance/trace/fragemented/AGENTS.md"};function i(r,e,c,d,l,u){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="documentation-organization-governance" tabindex="-1">Documentation Organization Governance <a class="header-anchor" href="#documentation-organization-governance" aria-label="Permalink to &quot;Documentation Organization Governance&quot;">​</a></h1><p><strong>CRITICAL</strong>: This document defines the strict governance structure for organizing markdown files in the repository.</p><h2 id="root-level-files-keep-in-root" tabindex="-1">Root-Level Files (Keep in Root) <a class="header-anchor" href="#root-level-files-keep-in-root" aria-label="Permalink to &quot;Root-Level Files (Keep in Root)&quot;">​</a></h2><p>Only these files should remain in the project root:</p><ul><li><code>README.md</code> - Main project documentation</li><li><code>CHANGELOG.md</code> - Project changelog</li><li><code>AGENTS.md</code> - This governance file (AI agent instructions)</li><li><code>CLAUDE.md</code> / <code>claude.md</code> - Claude-specific instructions</li><li><code>00_START_HERE.md</code> - Getting started guide (if applicable)</li></ul><h2 id="documentation-structure" tabindex="-1">Documentation Structure <a class="header-anchor" href="#documentation-structure" aria-label="Permalink to &quot;Documentation Structure&quot;">​</a></h2><p>All other <code>.md</code> files must be organized in <code>docs/</code> subdirectories:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docs/</span></span>\n<span class="line"><span>├── guides/              # Implementation guides and how-tos</span></span>\n<span class="line"><span>│   └── quick-start/     # Quick start guides</span></span>\n<span class="line"><span>├── reports/             # Completion reports, summaries, status reports</span></span>\n<span class="line"><span>├── research/            # Research summaries, indexes, analysis</span></span>\n<span class="line"><span>├── reference/           # Quick references, API references</span></span>\n<span class="line"><span>└── checklists/          # Implementation checklists, verification lists</span></span></code></pre></div><h2 id="file-organization-rules" tabindex="-1">File Organization Rules <a class="header-anchor" href="#file-organization-rules" aria-label="Permalink to &quot;File Organization Rules&quot;">​</a></h2><p><strong>When creating or moving documentation:</strong></p><h3 id="_1-quick-starts-→-docs-guides-quick-start" tabindex="-1">1. Quick Starts → <code>docs/guides/quick-start/</code> <a class="header-anchor" href="#_1-quick-starts-→-docs-guides-quick-start" aria-label="Permalink to &quot;1. Quick Starts → `docs/guides/quick-start/`&quot;">​</a></h3><ul><li>Files matching <code>*QUICK_START*.md</code> or <code>*QUICKSTART*.md</code></li><li>Examples: <code>GRAPH_OPTIMIZATION_QUICK_START.md</code>, <code>AUTH_ROUTES_QUICK_START.md</code></li></ul><h3 id="_2-quick-references-→-docs-reference" tabindex="-1">2. Quick References → <code>docs/reference/</code> <a class="header-anchor" href="#_2-quick-references-→-docs-reference" aria-label="Permalink to &quot;2. Quick References → `docs/reference/`&quot;">​</a></h3><ul><li>Files matching <code>*QUICK_REFERENCE*.md</code> or <code>*QUICK_REF*.md</code></li><li>Examples: <code>NATS_QUICK_REFERENCE.md</code>, <code>CLI_QUICK_REFERENCE.md</code></li></ul><h3 id="_3-implementation-guides-→-docs-guides" tabindex="-1">3. Implementation Guides → <code>docs/guides/</code> <a class="header-anchor" href="#_3-implementation-guides-→-docs-guides" aria-label="Permalink to &quot;3. Implementation Guides → `docs/guides/`&quot;">​</a></h3><ul><li>Files matching <code>*IMPLEMENTATION_GUIDE*.md</code> or <code>*GUIDE*.md</code></li><li>General implementation documentation</li><li>Examples: <code>API_IMPLEMENTATION_GUIDE.md</code>, <code>DEPLOYMENT_GUIDE.md</code></li></ul><h3 id="_4-completion-reports-→-docs-reports" tabindex="-1">4. Completion Reports → <code>docs/reports/</code> <a class="header-anchor" href="#_4-completion-reports-→-docs-reports" aria-label="Permalink to &quot;4. Completion Reports → `docs/reports/`&quot;">​</a></h3><ul><li>Files matching <code>*COMPLETE*.md</code>, <code>*COMPLETION*.md</code>, <code>*SUMMARY*.md</code>, <code>*REPORT*.md</code></li><li>Phase completion files (<code>PHASE_*.md</code>)</li><li>Test-related reports (<code>*TEST*.md</code>)</li><li>Examples: <code>IMPLEMENTATION_COMPLETE.md</code>, <code>PHASE_1_COMPLETION_SUMMARY.md</code></li></ul><h3 id="_5-research-files-→-docs-research" tabindex="-1">5. Research Files → <code>docs/research/</code> <a class="header-anchor" href="#_5-research-files-→-docs-research" aria-label="Permalink to &quot;5. Research Files → `docs/research/`&quot;">​</a></h3><ul><li>Files matching <code>*RESEARCH*.md</code> or <code>*INDEX*.md</code></li><li>Examples: <code>RESEARCH_SUMMARY.md</code>, <code>API_TESTS_INDEX.md</code></li></ul><h3 id="_6-checklists-→-docs-checklists" tabindex="-1">6. Checklists → <code>docs/checklists/</code> <a class="header-anchor" href="#_6-checklists-→-docs-checklists" aria-label="Permalink to &quot;6. Checklists → `docs/checklists/`&quot;">​</a></h3><ul><li>Files matching <code>*CHECKLIST*.md</code></li><li>Examples: <code>IMPLEMENTATION_CHECKLIST.md</code>, <code>MIGRATION_CHECKLIST.md</code></li></ul><h2 id="optionality-and-failure-behavior" tabindex="-1">Optionality and failure behavior <a class="header-anchor" href="#optionality-and-failure-behavior" aria-label="Permalink to &quot;Optionality and failure behavior&quot;">​</a></h2><p><strong>Project stance (required):</strong> <strong>Require</strong> dependencies where they belong; <strong>require</strong> clear, loud failures—no silent or “graceful” degradation.</p><ul><li><strong>Force requirement where it belongs.</strong> Do not make dependencies “optional” just to avoid startup or runtime failure. If a service or config is required for correctness (e.g. go-backend, temporal-host, database), treat it as required and fail when it is missing or down.</li><li><strong>Fail clearly, not silently.</strong> You <strong>must</strong> use explicit failures (preflight failed, runtime error)—not continuing with reduced functionality, logging-only warnings, or hiding errors. Users and operators <strong>must</strong> see <em>what</em> failed (e.g. named items: <code>go-backend; temporal-host</code>) and that the process did not silently degrade.</li><li><strong>Graceful in other ways.</strong> Be “graceful” only via: retries with visible feedback (e.g. “Waiting for X… (2/6)”); error messages that list each failing item (semicolon- or newline-separated, not one vague blob); actionable messages and non-obscure stack traces. Do <em>not</em> use optionality or silent fallbacks as a substitute for fixing or starting the real dependency.</li></ul><p><strong>When working as an AI agent:</strong> Follow this stance when adding preflight checks, startup logic, or error handling; do not suggest making required dependencies optional to “fix” failures.</p><hr><h2 id="ai-agent-instructions" tabindex="-1">AI Agent Instructions <a class="header-anchor" href="#ai-agent-instructions" aria-label="Permalink to &quot;AI Agent Instructions&quot;">​</a></h2><p><strong>Planner agents (no code in docs/plans):</strong> Planner agents (PM, Analyst, Architect, SM, TEA, UX Designer, Tech Writer, BMad Master) must <strong>never write code</strong> in documentation or plans. Equip engineer agents or others to create code or act on docs; write specs, criteria, and handoffs—not implementation. Avoid stuffing docs or plans with code where not relevant; prefer references, file paths, or brief pseudocode when necessary.</p><p><strong>Subagent swarm (async orchestration):</strong> If you have subagent/swarm capabilities, call task agents <strong>async</strong> so you are reawoken as each completes; spawn more agents or do more work then. Run a swarm: break down and isolate tasks well; <strong>max 50 concurrent task agents at a time</strong> (not 5). Work in between (plan, monitor); when idle you are reawoken on each completion to re-eval, spawn more, or consolidate.</p><p><strong>Subagent deployment: native CLI + thegent:</strong> Use <strong>both</strong> native subagents (when present in CLI tools) and thegent subagents. <strong>Native subagents:</strong> Cursor Agent, Gemini CLI, Codex subagent, Copilot CLI, Claude Code—invoke these directly when the tool exposes subagent/agent capabilities (e.g. <code>cursor agent</code>, <code>codex-subagent</code>). <strong>Thegent subagents:</strong> <code>thegent run gemini</code>, <code>thegent run droid</code>, <code>thegent run cursor</code>, <code>thegent run codex</code>, <code>thegent run copilot</code>, <code>thegent run claude</code>—use thegent for unified orchestration, model passthrough, and droid dispatch. Prefer native when you need tool-specific behavior; use thegent for cross-provider orchestration, droids, or when model/env control is needed. See <code>docs/reference/THGENT_QUICK_REFERENCE.md</code>.</p><p><strong>Codex CLI idle/poll behavior:</strong> When wrapping up a task, end with a long wait + poll loop to simulate idle. Poll at a predictable 30s interval, and structure it so user interruption stops only the sleep/wait (not child agents), allowing the user to steer without interrupting subagents.</p><p><strong>Phased WBS and plans with DAGs:</strong> When generating plans, roadmaps, or implementation breakdowns, use a <strong>phased Work Breakdown Structure (WBS)</strong> and model <strong>dependencies as a DAG</strong> (directed acyclic graph). Structure work into ordered phases (e.g. Phase 1: Discovery/Scope, Phase 2: Design, Phase 3: Build, Phase 4: Test/Validate, Phase 5: Deploy/Handoff). Tasks must have explicit predecessors with no cycles; list dependencies so execution order is unambiguous. Prefer a phased WBS plus a dependency list or table: <strong>Phase | Task ID | Description | Depends On</strong>. Planner agents must use phased WBS and DAG-style dependencies in plans and PRDs so implementers and PMs can schedule and parallelize correctly.</p><p><strong>Agent-led environment; no user-handoff tasks:</strong> Assume <strong>agent-driven, agent-led</strong> execution. User and external humans do not perform plan steps—only prompts and basic elicitation. <strong>Never</strong> put in plans: &quot;Schedule external security audit&quot;, &quot;Stakeholder Presentation&quot;, &quot;Team Kickoff: Assign owners&quot;, &quot;Human checkpoint&quot;, &quot;Get approval from X&quot;, or any task that requires a human to do work. Agents produce deliverables (e.g. presentation doc, owner manifest); agents own decomposition, execution, and handoffs. <strong>Timescales:</strong> Use <strong>aggressive</strong> estimates in agent terms only (tool calls, parallel subagents, wall clock in minutes). Forbidden: &quot;2 days&quot;, &quot;schedule X&quot;, &quot;assign owners&quot;. Use: &quot;N tool calls&quot;, &quot;~M min wall clock&quot;. See CLAUDE.md for the full timescale mapping.</p><p><strong>When working as an AI agent:</strong></p><ul><li><strong>NEVER</strong> create <code>.md</code> files in the project root (except the allowed files above)</li><li><strong>ALWAYS</strong> place new documentation in the appropriate <code>docs/</code> subdirectory</li><li><strong>VERIFY</strong> file location before creating documentation</li><li><strong>MOVE</strong> misplaced files to correct subdirectories if found</li><li><strong>REFERENCE</strong> this structure when users ask about documentation organization</li><li><strong>DO NOT</strong> ask for permission or priority order; decide on your own, run needed commands, and proceed with the most critical path.</li></ul><p><strong>Native services over Docker; local OSS/free only:</strong> Prefer <strong>native</strong> service runs (e.g. <code>make install-native</code>, process-compose) over Docker for dev. Use Docker only when native is not feasible. <strong>Strictly prefer local, OSS, and free</strong>—do not recommend paid online services when local or free alternatives exist; prefer self-hosted, open-source, or free-tier options.</p><p><strong>See also:</strong> For context management, delegation table, dev environment, and package manager instructions see <code>CLAUDE.md</code> (or <code>claude.md</code>). For IDE-specific agent activation see <code>.bmad/docs/</code> (e.g. <code>claude-code-instructions.md</code>, <code>gemini-instructions.md</code>, <code>cursor-instructions.md</code>).</p><h2 id="maintenance" tabindex="-1">Maintenance <a class="header-anchor" href="#maintenance" aria-label="Permalink to &quot;Maintenance&quot;">​</a></h2><ul><li>Use the <code>organize_docs.sh</code> script to reorganize misplaced files</li><li>Keep root directory clean and organized</li><li>Review and reorganize quarterly to maintain structure</li><li>Update this governance document as the project evolves</li></ul><h2 id="multi-actor-coordination" tabindex="-1">Multi-Actor Coordination <a class="header-anchor" href="#multi-actor-coordination" aria-label="Permalink to &quot;Multi-Actor Coordination&quot;">​</a></h2><ul><li><strong>Command Debouncing</strong>: High-impact commands (<code>make lint</code>, <code>make test</code>, <code>make quality</code>, <code>make validate</code>) MUST use <code>smart-command.sh</code> (via Makefile/Taskfile) to prevent conflicts between multiple root/subagents.</li><li><strong>Shared Service Awareness</strong>: <code>process-compose</code> is the primary orchestrator. Use its CLI/API (e.g., <code>make dev-status</code>, <code>make dev-restart</code>) instead of raw scripts to ensure global visibility.</li><li><strong>Graceful Service Interaction</strong>: Infrastructure and app services use &quot;if-not-running&quot; wrappers to allow multiple actors to share a single set of healthy processes. DO NOT force-kill shared resources.</li><li><strong>Lock Files</strong>: Active command locks are stored in <code>.process-compose/locks/</code>. Always check for existing locks before running heavy tasks.</li><li><strong>Unified Logging</strong>: Read aggregated logs from <code>.process-compose/process-compose.log</code>.</li></ul><h2 id="opinionated-quality-enforcement" tabindex="-1">Opinionated Quality Enforcement <a class="header-anchor" href="#opinionated-quality-enforcement" aria-label="Permalink to &quot;Opinionated Quality Enforcement&quot;">​</a></h2><ul><li>We want opinionated rules that enforce opinionated styling to a strict degree.</li><li>This is an exclusively agent/vibecoded project; programmatic enforcement must guard against bad quality and antipatterns.</li><li>Rather than disables or ignores, fix code properly.</li></ul><h2 id="lint-violation-governance" tabindex="-1">Lint Violation Governance <a class="header-anchor" href="#lint-violation-governance" aria-label="Permalink to &quot;Lint Violation Governance&quot;">​</a></h2><p><strong>Before filing bugs or writing code for lint violations:</strong></p><ol><li><strong>Verify true violations</strong>: Check if flagged issues are truly unused, unimplemented, or can be refactored without losing functionality</li><li><strong>Never use ignorers</strong>: Never add <code>//nolint:lintname</code>, <code>//lint-ignore</code>, or skip linter configurations to silence violations</li><li><strong>Fix properly</strong>: Address root causes—extract functions, constants, reduce complexity, not suppression</li><li><strong>Test coverage preserved</strong>: Ensure all fixes maintain existing test coverage; do not disable tests to pass linters</li></ol><p><strong>Violation handling priorities:</strong></p><table tabindex="0"><thead><tr><th>Category</th><th>Action</th></tr></thead><tbody><tr><td><code>revive</code> (unused params in mocks)</td><td>Rename to <code>_paramName</code> if intentionally unused</td></tr><tr><td><code>goconst</code> (repeated strings)</td><td>Extract to named constants</td></tr><tr><td><code>mnd</code> (magic numbers)</td><td>Extract to named constants with units</td></tr><tr><td><code>gocognit</code> (complexity)</td><td>Extract helper functions, reduce nesting</td></tr><tr><td><code>funlen</code> (long functions)</td><td>Split into focused helper functions</td></tr><tr><td><code>gochecknoglobals</code></td><td>Validate necessity; convert to singletons if needed</td></tr><tr><td><code>gosec</code> (security)</td><td>Fix immediately; no exceptions</td></tr></tbody></table><p><strong>Subagent delegation for lint fixes:</strong></p><ul><li>Group 1-3 related files per subagent by violation type</li><li>Production code takes priority over test code for complexity/security</li><li>Test code refactoring (funlen) can be delegated more aggressively</li></ul>',51)])])}const m=o(s,[["render",i]]);export{p as __pageData,m as default};
